sqlMap.insert:
INSERT INTO WeavePattern (
    Name, Code, RepeatX, RepeatY,
    Cells, WarpColors, WeftColors,
    WarpThickness, WeftThickness,
    WeaveMode, SavedAt
) VALUES (
    @name, @code, @repeatX, @repeatY,
    @cells, @warpColors, @weftColors,
    @warpThickness, @weftThickness,
    @weaveMode, @savedAt
)
ON CONFLICT(Code) DO UPDATE SET
    Name          = @name,
    RepeatX       = @repeatX,
    RepeatY       = @repeatY,
    Cells         = @cells,
    WarpColors    = @warpColors,
    WeftColors    = @weftColors,
    WarpThickness = @warpThickness,
    WeftThickness = @weftThickness,
    WeaveMode     = @weaveMode,
    SavedAt       = @savedAt;

sqlMap.create:
CREATE TABLE IF NOT EXISTS Colors (
    Idx    INTEGER PRIMARY KEY AUTOINCREMENT,
    Key    TEXT    NOT NULL UNIQUE,
    Value  TEXT    NOT NULL
);

sqlMap.update:
UPDATE WeavePattern
SET Name = @name
WHERE Code = @code;
